# DK STS.  Struer - Thisted
#
let st = path("d3.dk.sts");

with detail = 3, railway = :first :pax {
    # point.dk.Struer  dk.LES

    with link = "point.dk.Struer-Havneplads", railway = :station {
        track(st[:str + 300m, :sha + 0.5sw]);
        marker(:right :de.hp :removed, st[:sha] >> 0.5mt);
        slabel(:right :removed, st[:sha] >> 0.5mt >> 1sh + (1dt, 0dt),
            "Struer Havneplads"
        );
    }

    with link = "line.dk.STS" {
        track(st[:sha + 0.49sw, :bre - 0.49sw]);
    }

    with link = "point.dk.Bremdal", railway = :station {
        track(st[:bre - 0.5sw, :bre + 0.5sw]);
        marker(:right :de.hp :removed, st[:bre] >> 0.5mt);
        slabel(:right :removed, st[:bre] >> 0.5mt >> 1sh + (1.3dt, 0.8dt),
            "Bremdal"
        );
    }

    with link = "line.dk.STS" {
        track(st[:bre + 0.49sw, :bre + 1.31km]);
        line_label(:right:sw, st[:bre + 1.3km] >> 0.5mt, "STS");
        track(st[:bre + 1.29km, :hum - 0.49sw]);
    }

    with link = "point.dk.Humlum", railway = :station {
        track(st[:hum - 0.5sw, :hum + 0.5sw]);
        marker(:left :de.hp, st[:hum] << 0.5mt);
        slabel(:left, st[:hum] << 0.5mt << 1sh + (-1.3dt, 1.0dt),
            "Humlum"
        );
    }

    with link = "line.dk.STS" {
        track(st[:hum + 0.49sw, :ods.ys]);
    }

    with link = "point.dk.Oddesund-Syd", railway = :station :removed {
        let ods = path("d3.dk.sts.ods");

        track(ods[:ods.ys, :ods + 0.6sw]);
        marker(:right :de.bf, ods[:ods] >> 0.5mt);
        slabel(:right, ods[:ods] >> 0.5mt >> 1sh + (1.3dt, 1.2dt),
            "Oddesund Syd"
        );
    }

    with link = "line.dk.STS" {
        track(st[:ods.ys - 0.1dl, :odn - 0.49sw]);
    }

    with link = "point.dk.Oddesund-Nord", railway = :station {
        track(st[:odn - 0.5sw, :odn + 0.5sw]);
        marker(:left :de.hp, st[:odn] << 0.5mt);
        marker(:left :de.exbf, st[:odn] << 0.5mt);
        slabel(:ne, st[:odn] << 0.5mt << 1.4sh + (3dt, 0.4dt),
            "Oddesund Nord"
        );
    }

    with link = "line.dk.STS" {
        track(st[:odn + 0.49sw, :ugl - 0.49sw]);
    }

    with link = "point.dk.Uglev", railway = :station {
        track(st[:ugl - 0.5sw, :ugl + 0.5sw]);
        marker(:left :de.hp, st[:ugl] << 0.5mt);
        marker(:left :de.exbf, st[:ugl] << 0.5mt);
        slabel(:left, st[:ugl] << 0.5mt << 1.4sh + (-1.3dt, 0.8dt),
            "Uglev"
        );
    }

    with link = "line.dk.STS" {
        track(st[:ugl + 0.49sw, :hvi - 0.49sw]);
    }

    with link = "point.dk.Hvidbjerg", railway = :station {
        track(st[:hvi - 0.5sw, :hvi + 0.5sw]);
        marker(:right :de.bf, st[:hvi] >> 0.5mt);
        slabel(:right, st[:hvi] >> 0.5mt >> 1sh + (1.7dt, 0.4dt),
            "Hvidbjerg"
        );
    }

    with link = "line.dk.STS" {
        track(st[:hvi + 0.49sw, :lyn - 0.49sw]);
    }

    with link = "point.dk.Lyngs", railway = :station {
        track(st[:lyn - 0.5sw, :lyn + 0.5sw]);
        marker(:right :de.hp, st[:lyn] >> 0.5mt);
        marker(:right :de.exbf, st[:lyn] >> 0.5mt);
        slabel(:top, st[:lyn] >> 0.5mt >> 1.4sh + (0.7dt, -0.5dt),
            "Lyngs"
        );
    }

    with link = "line.dk.STS" {
        track(st[:lyn + 0.49sw, :ydb - 0.49sw]);
    }

    with link = "point.dk.Ydby", railway = :station {
        track(st[:ydb - 0.5sw, :ydb + 0.5sw]);
        marker(:left :de.hp, st[:ydb] << 0.5mt);
        marker(:left :de.exbf, st[:ydb] << 0.5mt);
        slabel(:left, st[:ydb] << 0.5mt << 1.4sh + (-1.3dt, 0.8dt),
            "Ydby"
        );
    }

    with link = "line.dk.STS" {
        track(st[:ydb + 0.49sw, :hur - 0.49sw]);
    }

    with link = "point.dk.Hurup-Thy", railway = :station {
        track(st[:hur - 0.5sw, :hur + 0.5sw]);
        marker(:left :de.bf, st[:hur] << 0.5mt);
        slabel(:left, st[:hur] << 0.5mt << 1sh + (-1.3dt, 0.8dt),
            "Hurup Thy"
        );
    }

    with link = "line.dk.STS" {
        track(st[:hur + 0.49sw, :bed - 0.49sw]);
    }

    with link = "point.dk.Bedsted-Thy", railway = :station {
        track(st[:bed - 0.5sw, :bed + 0.5sw]);
        marker(:left :de.bf, st[:bed] << 0.5mt);
        slabel(:left, st[:bed] << 0.5mt << 1sh + (-1.5dt, 0.3dt),
            "Bedsted Thy"
        );
    }

    with link = "line.dk.STS" {
        track(st[:bed + 0.49sw, :has - 0.49sw]);
    }

    with link = "point.dk.Hassing", railway = :station {
        track(st[:has - 0.5sw, :has + 0.5sw]);
        marker(:left :de.hst :removed, st[:has] << 0.5mt);
        slabel(:left :removed, st[:has] << 0.5mt << 1sh + (-1.8dt, 0.3dt),
            "Hassing"
        );
    }

    with link = "line.dk.STS" {
        track(st[:has + 0.49sw, :hor - 0.49sw]);
    }

    with link = "point.dk.Hørdum", railway = :station {
        track(st[:hor - 0.5sw, :hor + 0.5sw]);
        marker(:right :de.hp, st[:hor] >> 0.5mt);
        marker(:right :de.exbf, st[:hor] >> 0.5mt);
        slabel(:right, st[:hor] >> 0.5mt >> 1.4sh + (1.6dt, 1.5dt),
            "Hørdum"
        );
    }

    with link = "line.dk.STS" {
        track(st[:hor + 0.49sw, :sne - 0.49sw]);
    }

    with link = "point.dk.Snedsted", railway = :station {
        track(st[:sne - 0.5sw, :sne + 0.5sw]);
        marker(:left :de.bf, st[:sne] << 0.5mt);
        slabel(:left, st[:sne] << 0.5mt << 1sh + (-1.4dt, 0.7dt),
            "Snedsted"
        );
    }

    with link = "line.dk.STS" {
        track(st[:hor + 0.49sw, :sne - 0.49sw]);
    }

    with link = "point.dk.Snedsted", railway = :station {
        track(st[:sne - 0.5sw, :sne + 0.5sw]);
        marker(:left :de.bf, st[:sne] << 0.5mt);
        slabel(:left, st[:sne] << 0.5mt << 1sh + (-1.4dt, 0.7dt),
            "Snedsted"
        );
    }

    with link = "line.dk.STS" {
        track(st[:sne + 0.49sw, :tod - 0.49sw]);
    }

    with link = "point.dk.Todbøl", railway = :station {
        track(st[:tod - 0.5sw, :tod + 0.5sw]);
        marker(:right :de.hp :removed, st[:tod] >> 0.5mt);
        slabel(:right :removed, st[:tod] >> 0.5mt >> 1sh + (1.3dt, 1.3dt),
            "Todbøl"
        );
    }

    with link = "line.dk.STS" {
        track(st[:tod + 0.49sw, :sjo - 0.49sw]);
    }

    with link = "point.dk.Sjørring", railway = :station {
        track(st[:sjo - 0.5sw, :sjo + 0.5sw]);
        marker(:left :de.hp, st[:sjo] << 0.5mt);
        marker(:left :de.exbf, st[:sjo] << 0.5mt);
        slabel(:left, st[:sjo] << 0.5mt << 1.4sh + (-1.4dt, 0.8dt),
            "Sjørring"
        );
    }

    with link = "line.dk.STS" {
        track(st[:sjo + 0.49sw, :thi.yf - 0.9seg]);
        track(:lor, st[:thi.yf - 1seg, :thi.yf]);
        track(:lor, st[:thi.yf, :thi - 0.49sw]);
    }

    with link = "point.dk.Thisted", railway = :station {
        track(:removed, st[:thi - 0.5sw, :thi + 0.5sw] << 1ms << 1mt);
        track(st[:thi - 0.5sw, :thi + 0.5sw]);
        marker(:left :de.bf, st[:thi] << 1ms << 1.5mt);
        slabel(:top :bold, st[:thi] << 1ms << 1.5mt << 1sh + (0.5dt, -0.4dt),
            "Thisted"
        );
    }
}

